-- Seed b1Bank MAX COMMERCIAL MM (XXXXXX3920) transactions and balance snapshots
-- Source: AccountHistory.csv export from b1Bank

BEGIN;

-- ── Transactions ────────────────────────────────────────────────────────────
ON CONFLICT (plaid_id) DO UPDATE SET
  account_id = EXCLUDED.account_id,
  date = EXCLUDED.date,
  amount = EXCLUDED.amount,
  name = EXCLUDED.name,
  merchant_name = EXCLUDED.merchant_name,
  pending = EXCLUDED.pending,
  current_balance = EXCLUDED.current_balance,
  account_owner = EXCLUDED.account_owner,
  account_name = EXCLUDED.account_name,
  account_type = EXCLUDED.account_type,
  source = EXCLUDED.source,
  updated_at = NOW();

-- ── Daily Balance Snapshots ─────────────────────────────────────────────────
-- Use the latest balance per date (some dates have multiple transactions)
ON CONFLICT (account_id, snapshot_date) DO UPDATE SET
  current_balance = EXCLUDED.current_balance,
  source = EXCLUDED.source;

COMMIT;
